try{
if( Date.now() < message.payload.timeoutBeforeEscalationTS.value){
 goTo('out1');
}else{
 goTo('out2');
}
}catch(err){
message.payload.lastException = e.toString();
 goTo('err')
}

try {
     const max = message.payload.currentList.value === 'main' ? message.payload.numUsersMainList.value : message.payload.numUsersBackupList.value;
    message.payload.idxLoop.value++;
    if (message.payload.idxLoop.value < max) {
        goTo('out1');
    } else {
        goTo('out2');
    }
} catch (e) {
    message.payload.lastException = e.toString();
    goTo('err');
}

try {
    if (message.payload.idxRetries.value < message.payload.retries.value) {
        message.payload.idxRetries.value++;
        // reset idx
        message.payload.idxLoop.value = 0;

        goTo('out1');
    } else {
        if (message.payload.fallbackOnDeptMembers?.value === true && message.payload.currentList.value !== 'backup'
            && message.payload.backupList && message.payload.numUsersBackupList?.value > 0) {
            message.payload.currentList.value = 'backup';
            message.payload.collaboratorList.value = message.payload.backupList.value;

            // reset loop vars
            message.payload.idxLoop.value = 0;
            message.payload.idxRetries.value = 0;
            goTo('out3');
        } else {
            goTo('out2');
        }

    }
} catch (e) {
    message.payload.lastException = e.toString();
    goTo('err');
}

try {
    // Check if we go next or stop here
    if (message.payload.loopForwardDestIdx.value < message.payload.escalationForwardDest.value.length) {
        message.payload.forwardDest.value = message.payload.escalationForwardDest.value[message.payload.loopForwardDestIdx.value];
        goTo('out1');
    } else {
        goTo('out2');

    }
} catch (e) {
    goTo('err');
}

try {

    message.payload.numForwardDest = { value: message.payload.escalationForwardDest.value.length, type: 'int' };
    message.payload.loopForwardDestIdx = { value: 0, type: 'int' };

    if (message.payload.numForwardDest.value > 0) {
        goTo('out1');
    } else {
        goTo('out2');
    }
} catch (e) {
    goTo('err');
}

try {

    if (message.payload.mainList != undefined) {
        message.payload.numUsersMainList = { type: 'int', value: message.payload.mainList.value.length };
        message.payload.currentList = { type: 'string', value: 'main' };
        message.payload.collaboratorList = { type: 'object', value: message.payload.mainList.value };
    } else {
        message.payload.numUsersMainList = { type: 'int', value: 0 };
    }

    if (message.payload.backupList != undefined) {
        message.payload.numUsersBackupList = { type: 'int', value: message.payload.backupList.value.length };
    } else {
        message.payload.numUsersBackupList = { type: 'int', value: 0 };
    }

    message.payload.timeoutBeforeEscalationTS = {
        type: 'int', value: Date.now() + (message.payload?.timeoutBeforeEscalation?.value || 600) * 1000,
    };

    message.payload.idxRetries = { type: 'int', value: 0 };
    message.payload.idxLoop = { type: 'int', value: 0 };

    if (message.payload.numUsersMainList.value > 0) {
        goTo('out1');
    } else if (message.payload.numUsersBackupList.value > 0) {
        message.payload.currentList.value = 'backup';
        message.payload.collaboratorList.value = message.payload.backupList.value;
        goTo('out1');
    } else {
        goTo('out2');
    }

} catch (e) {
    message.payload.lastException = e.toString();
    goTo('err');
}

try {

    // Update CDR
    message.payload.cdrRecord.value.escalations.push({
        'telNr': message.payload.forwardDest.value.toString(),
        'status': 'timeout',
    });
    message.payload.loopForwardDestIdx.value++;
    goTo('out1')

} catch (e) {
    message.payload.lastException = e.toString();
    goTo('err');
}
